// Check whether Meta story delivery is enabled and filter to story-eligible alerts.
// Eligible: importance_score >= META_ALERT_STORY_THRESHOLD (default 80)
// and at least one Meta platform has stories enabled.

const enableInstagram = ($vars.ENABLE_META_INSTAGRAM || '').toLowerCase() === 'true';
const enableFacebook  = ($vars.ENABLE_META_FACEBOOK  || '').toLowerCase() === 'true';
const enableIgStory   = ($vars.ENABLE_META_INSTAGRAM_STORIES || '').toLowerCase() === 'true';
const enableFbStory   = ($vars.ENABLE_META_FACEBOOK_STORIES  || '').toLowerCase() === 'true';

const storyEnabled = (enableInstagram && enableIgStory) || (enableFacebook && enableFbStory);

if (!storyEnabled) {
  return [{ json: { _meta_skip: true, reason: 'No Meta story platforms enabled' } }];
}

const threshold = parseInt($vars.META_ALERT_STORY_THRESHOLD || '80', 10);

const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];

const eligible = items.filter(i =>
  i.importance_score >= threshold &&
  (i.channels || []).includes('telegram') // already approved for alerting
);

if (eligible.length === 0) {
  return [{ json: { _meta_skip: true, reason: `No alerts met story threshold (>= ${threshold})` } }];
}

return eligible.map(item => ({
  json: {
    ...item,
    _meta_enable_ig_story: enableInstagram && enableIgStory,
    _meta_enable_fb_story: enableFacebook  && enableFbStory,
    _meta_skip: false
  }
}));

// Format the alert as a Meta story asset.
// Stories are short, visual, and punchy — no long body text.
const item = $input.item.json;

const topicEmoji = {
  crypto:     '🪙',
  finance:    '📈',
  economy:    '🏦',
  health:     '🏥',
  ai:         '🤖',
  energy:     '⚡',
  technology: '💻'
};
const emoji = topicEmoji[item.topic_slug] || '📰';

// Truncate headline to ~120 chars for story caption
const truncate = (s, n) => s && s.length > n ? s.slice(0, n - 1) + '…' : (s || '');
const storyCaption = `${emoji} ${truncate(item.headline, 120)}`;

// Build per-platform story caption (same for now, but kept separate for future divergence)
const igStoryCaption = item._meta_enable_ig_story ? storyCaption : null;
const fbStoryCaption = item._meta_enable_fb_story ? storyCaption : null;

const storyAsset = {
  topic_slug:   item.topic_slug,
  date_key:     item.event_at ? item.event_at.slice(0, 10) : new Date().toISOString().slice(0, 10),
  asset_type:   'story',
  source_type:  'alert',
  source_id:    item.item_id || item.alert_id?.toString() || null,
  publish_job_id: null,
  ai_output: {
    post_caption:          item.summary_text || item.headline,
    hashtags:              [`#${item.topic_slug}`, '#breakingnews'],
    image_prompt:          `Urgent news background for ${item.topic_slug} story`,
    story_caption:         storyCaption,
    story_background_hint: `High-impact ${item.topic_slug} news visual`,
    cta:                   null
  },
  instagram: {
    enabled:       !!item._meta_enable_ig_story,
    caption:       igStoryCaption || '',
    story_caption: igStoryCaption,
    story_enabled: !!item._meta_enable_ig_story
  },
  facebook: {
    enabled:       !!item._meta_enable_fb_story,
    caption:       fbStoryCaption || '',
    story_caption: fbStoryCaption,
    story_enabled: !!item._meta_enable_fb_story
  },
  generated_at: new Date().toISOString(),
  // carry original alert fields for downstream D1 logging
  _source_alert: {
    item_id:          item.item_id,
    importance_score: item.importance_score,
    severity_score:   item.severity_score,
    headline:         item.headline
  }
};

return [{ json: storyAsset }];

// Dispatch the story to Instagram and/or Facebook.
// Stories go to the appropriate Meta Graph API story endpoints.
//
// Instagram Story: POST /{ig-user-id}/media  with media_type=STORIES
// Facebook Story:  POST /{page-id}/photo_stories  (requires image URL)
//
// For v1, caption-only stories (no image URL) are submitted.
// Production deployments should attach an image URL from the image pipeline.

const asset = $input.item.json;
const results = [];

const igUserId = $vars.META_INSTAGRAM_USER_ID  || null;
const fbPageId = $vars.META_FACEBOOK_PAGE_ID   || null;
const igToken  = $vars.META_INSTAGRAM_TOKEN    || null;
const fbToken  = $vars.META_FACEBOOK_PAGE_TOKEN|| null;

// Collect tasks
const tasks = [];

if (asset.instagram.story_enabled && igUserId && igToken) {
  tasks.push({
    platform: 'instagram',
    url:   `https://graph.facebook.com/v19.0/${igUserId}/media`,
    body:  { caption: asset.instagram.story_caption, media_type: 'STORIES', access_token: igToken },
    caption: asset.instagram.story_caption,
    source_id: asset.source_id
  });
}

if (asset.facebook.story_enabled && fbPageId && fbToken) {
  tasks.push({
    platform: 'facebook',
    url:   `https://graph.facebook.com/v19.0/${fbPageId}/photo_stories`,
    body:  { message: asset.facebook.story_caption, access_token: fbToken },
    caption: asset.facebook.story_caption,
    source_id: asset.source_id
  });
}

if (tasks.length === 0) {
  return [{ json: {
    _meta_skip: true,
    reason: 'No valid credentials or enabled story platforms for this alert',
    topic_slug: asset.topic_slug,
    date_key:   asset.date_key,
    source_id:  asset.source_id
  } }];
}

// Return each task as a separate item for individual dispatch
return tasks.map(t => ({ json: {
  ...t,
  topic_slug:   asset.topic_slug,
  date_key:     asset.date_key,
  asset_type:   'story',
  source_type:  'alert'
} }));

// Log result to D1.
const response = $input.item.json;
const task     = $('Resolve Story API Tasks').item.json;

const hasError = !!response.error;
const status   = hasError ? 'failed' : 'published';
const errMsg   = hasError ? `${response.error.message} [code: ${response.error.code}]` : null;
const postId   = response.id || null;

return [{ json: {
  _d1_sql: `INSERT INTO meta_social_publish_log
    (topic_slug, date_key, asset_type, source_type, source_id, platform, post_type,
     status, platform_post_id, error_message, attempt, created_at, updated_at)
  VALUES (?, ?, 'story', 'alert', ?, ?, 'story', ?, ?, ?, 1,
    strftime('%Y-%m-%dT%H:%M:%SZ','now'),
    strftime('%Y-%m-%dT%H:%M:%SZ','now')
  )`,
  _d1_params: [
    task.topic_slug,
    task.date_key,
    task.source_id || null,
    task.platform,
    status,
    postId,
    errMsg
  ],
  platform:  task.platform,
  status,
  post_id:   postId,
  error:     errMsg
} }];
